/* BTAlertDialog — Figma nodes 2519-1822 (web D) + 2519-2209 (mobile M → Flutter) */
/* All CSS vars verified against packages/tokens/platforms/web/bspace/dist/styles.css */

/* ── Overlay (backdrop) ──────────────────────────────────────────────────────── */

.bt-alert-dialog-overlay {
  position: fixed;
  inset: 0;
  z-index: 9100;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.5);
  animation: bt-alert-dialog-overlay-in 150ms ease;
}

@keyframes bt-alert-dialog-overlay-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

/* ── Dialog card ─────────────────────────────────────────────────────────────── */

.bt-alert-dialog {
  background: var(--bg-primary);
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-elevation-lg);
  width: 500px;
  padding: 24px var(--space-lg);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-xl);
  box-sizing: border-box;
  animation: bt-alert-dialog-in 150ms ease;
}

@keyframes bt-alert-dialog-in {
  from { opacity: 0; transform: scale(0.95); }
  to   { opacity: 1; transform: scale(1); }
}

/* ── Content ─────────────────────────────────────────────────────────────────── */

.bt-alert-dialog__content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-lg);
  width: 100%;
}

.bt-alert-dialog__media {
  width: 64px;
  height: 64px;
  padding: 10px;
  background: var(--bg-subtle);
  border-radius: var(--radius-lg);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  box-sizing: border-box;
}

.bt-alert-dialog__icon {
  width: 32px;
  height: 32px;
  display: block;
  flex-shrink: 0;
  /* SVG has fill="#64748B" (text-secondary) — no color override needed */
}

.bt-alert-dialog__text {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  text-align: center;
  width: 100%;
}

.bt-alert-dialog__title {
  font-size: var(--typography-font-size-lg);
  font-weight: 700;
  line-height: var(--typography-line-height-md);
  color: var(--text-primary);
  margin: 0;
}

.bt-alert-dialog__description {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  margin: 0;
}

.bt-alert-dialog__slot {
  width: 100%;
}

.bt-alert-dialog__actions {
  display: flex;
  gap: var(--space-sm);
  align-items: center;
  justify-content: center;
}

// BTAlertDialog types — Figma node 2519-1822 (web D, 500px).

export type BTAlertDialogVariant =
  | 'success'
  | 'warning'
  | 'confirmation'
  | 'info'
  | 'delete';

export interface BTAlertDialogProps {
  // Visual variant — controls icon, confirm button colour, and default label.
  variant: BTAlertDialogVariant;
  // Primary heading text.
  title: string;
  // Supporting description text.
  description: string;
  // Overrides the default confirm label ('Continue' or 'Delete').
  confirmLabel?: string;
  // Label for the cancel button. @default 'Cancel'
  cancelLabel?: string;
  // Whether to show the cancel (2nd) button. @default true
  has2ndButton?: boolean;
  // Controls dialog open/close state (v-model). @default false
  modelValue?: boolean;
  // Close dialog when backdrop is clicked. @default true
  closeOnOverlayClick?: boolean;
}
